// --- CONFIGURATION & GRID SETUP ---
const gridWidth = 20;
const gridHeight = 15;
const config = {
    penalty: 'manhattan', // Heuristic type
    adjacentCost: 1.414,  // Diagonal movement cost (sqrt of 2)
    traversalCost: 1,     // Orthogonal movement cost
    minIterations: 1000,  // Actually acts as a MAXIMUM iteration limit
    clearanceRatio: 0.25  // 25% chance for a cell to be an obstacle
};

// Generate 2D Grid
let grid = [];
for (let y = 0; y < gridHeight; y++) {
    grid[y] = [];
    for (let x = 0; x < gridWidth; x++) {
        // 1 represents an obstacle, 0 represents a walkable path
        grid[y][x] = Math.random() < config.clearanceRatio ? 1 : 0;
    }
}

// Define Start and End points
const startNode = { x: 0, y: 0 };
const endNode = { x: gridWidth - 1, y: gridHeight - 1 };

// Ensure start and end nodes are never generated as obstacles
grid[startNode.y][startNode.x] = 0;
grid[endNode.y][endNode.x] = 0;

// --- HELPER FUNCTIONS ---

// Calculates the heuristic (estimated distance to goal)
function calculateHeuristic(nodeA, nodeB) {
    let dx = Math.abs(nodeA.x - nodeB.x);
    let dy = Math.abs(nodeA.y - nodeB.y);

    if (config.penalty === 'manhattan') {
        return dx + dy; // Manhattan distance
    }
    return Math.sqrt((dx * dx) + (dy * dy)); // Euclidean distance
}

// Finds walkable neighbors (Original name: getAncestors)
function getNeighbors(node) {
    let neighbors = [];
    let directions = [
        { dx: 0, dy: -1, cost: config.traversalCost }, // Up
        { dx: 0, dy: 1, cost: config.traversalCost },  // Down
        { dx: -1, dy: 0, cost: config.traversalCost }, // Left
        { dx: 1, dy: 0, cost: config.traversalCost },  // Right
        { dx: -1, dy: -1, cost: config.adjacentCost }, // Top-Left
        { dx: 1, dy: -1, cost: config.adjacentCost },  // Top-Right
        { dx: -1, dy: 1, cost: config.adjacentCost },  // Bottom-Left
        { dx: 1, dy: 1, cost: config.adjacentCost }    // Bottom-Right
    ];

    for (let i = 0; i < directions.length; i++) {
        let nx = node.x + directions[i].dx;
        let ny = node.y + directions[i].dy;

        // Check bounds and ensure the cell is not an obstacle (0)
        if (nx >= 0 && nx < gridWidth && ny >= 0 && ny < gridHeight && grid[ny][nx] === 0) {
            neighbors.push({ x: nx, y: ny, moveCost: directions[i].cost });
        }
    }
    return neighbors;
}

// Creates a unique string key for nodes (e.g., "5,10")
function nodeKey(node) {
    return node.x + ',' + node.y;
}

// --- MAIN A* ALGORITHM ---

function findRoute(start, goal) {
    let openSet = {};   // Nodes to be evaluated
    let closedSet = {}; // Nodes already evaluated
    let cameFrom = {};  // Maps a node to its parent (used to retrace path)
    let gScore = {};    // Cost from start to a specific node
    let fScore = {};    // gScore + estimated cost to goal

    let startId = nodeKey(start);
    openSet[startId] = start;
    gScore[startId] = 0;
    fScore[startId] = calculateHeuristic(start, goal);

    let iterations = 0;

    // While there are nodes to evaluate and we haven't hit the loop limit
    while (Object.keys(openSet).length > 0 && iterations < config.minIterations) {
        iterations++;

        // Find the node in openSet with the lowest fScore
        let currentId = null;
        let lowestF = Infinity;
        for (let key in openSet) {
            if (fScore[key] < lowestF) {
                lowestF = fScore[key];
                currentId = key;
            }
        }

        let current = openSet[currentId];

        // Did we reach the goal?
        if (current.x === goal.x && current.y === goal.y) {
            let path = [current];
            let currKey = currentId;

            // Retrace steps backward to form the path
            while (cameFrom[currKey]) {
                currKey = cameFrom[currKey];
                // Lookup node from sets, or recreate it from string key
                path.push(openSet[currKey] || closedSet[currKey] || { 
                    x: parseInt(currKey.split(',')[0]), 
                    y: parseInt(currKey.split(',')[1]) 
                });
            }
            return { path: path, cost: gScore[currentId], iterations: iterations };
        }

        // Move current node from openSet to closedSet
        delete openSet[currentId];
        closedSet[currentId] = current;

        // Process neighbors
        let neighbors = getNeighbors(current);
        for (let i = 0; i < neighbors.length; i++) {
            let neighbor = neighbors[i];
            let neighborId = nodeKey(neighbor);

            // Skip if already evaluated
