            let tentative_gScore = gScore[currentId] + neighbor.moveCost;

            // If it's a new node or we found a shorter path to it
            if (gScore[neighborId] === undefined || tentative_gScore < gScore[neighborId]) {
                cameFrom[neighborId] = currentId;
                gScore[neighborId] = tentative_gScore;
                fScore[neighborId] = tentative_gScore + calculateHeuristic(neighbor, goal);
                openSet[neighborId] = neighbor;
            }
        }
    }

    // Path not found or iteration limit reached
    return { path: [], cost: Infinity, iterations: iterations };
}

// --- EXECUTION ---
